  1	import * as React from 'react';
  2	import { Divider, DropdownGroup, DropdownItem, Tooltip, TooltipPosition } from '@patternfly/react-core';
  3	import { serverConfig } from 'config';
  4	import { DestinationRule, getWizardUpdateLabel, K8sHTTPRoute, K8sGRPCRoute, VirtualService } from 'types/IstioObjects';
  5	import { canDelete, ResourcePermissions } from 'types/Permissions';
  6	import {
  7	  SERVICE_WIZARD_ACTIONS,
  8	  WIZARD_K8S_REQUEST_ROUTING,
  9	  WIZARD_K8S_GRPC_REQUEST_ROUTING,
 10	  WIZARD_EDIT_ANNOTATIONS,
 11	  WIZARD_TITLES,
 12	  WizardAction,
 13	  WizardMode,
 14	  WIZARD_REQUEST_ROUTING,
 15	  WIZARD_FAULT_INJECTION,
 16	  WIZARD_TRAFFIC_SHIFTING,
 17	  WIZARD_REQUEST_TIMEOUTS,
 18	  WIZARD_TCP_TRAFFIC_SHIFTING
 19	} from './WizardActions';
 20	import { hasServiceDetailsTrafficRouting } from '../../types/ServiceInfo';
 21	import { groupMenuStyle } from 'styles/DropdownStyles';
 22	import { kialiStyle } from 'styles/StyleUtils';
 23	import { t } from 'utils/I18nUtils';
 24	
 25	export const DELETE_TRAFFIC_ROUTING = 'delete_traffic_routing';
 26	
 27	type Props = {
 28	  annotations?: { [key: string]: string };
 29	  className?: string;
 30	  destinationRules: DestinationRule[];
 31	  isDisabled?: boolean;
 32	  istioPermissions: ResourcePermissions;
 33	  k8sGRPCRoutes: K8sGRPCRoute[];
 34	  k8sHTTPRoutes: K8sHTTPRoute[];
 35	  onAction?: (key: WizardAction, mode: WizardMode) => void;
 36	  onDelete?: (key: string) => void;
 37	  virtualServices: VirtualService[];
 38	};
 39	
 40	const optionDisabledStyle = kialiStyle({
 41	  cursor: 'not-allowed',
 42	  $nest: {
 43	    '& button': {
 44	      pointerEvents: 'none'
 45	    }
 46	  }
 47	});
 48	
 49	const dividerStyle = kialiStyle({
 50	  paddingTop: '0.5rem'
 51	});
 52	
 53	export const ServiceWizardActionsDropdownGroup: React.FunctionComponent<Props> = (props: Props) => {
 54	  const updateLabel = getWizardUpdateLabel(props.virtualServices, props.k8sHTTPRoutes, props.k8sGRPCRoutes);
 55	
 56	  const hasTrafficRouting = (): boolean => {
 57	    return hasServiceDetailsTrafficRouting(
 58	      props.virtualServices,
 59	      props.destinationRules,
 60	      props.k8sHTTPRoutes,
 61	      props.k8sGRPCRoutes
 62	    );
 63	  };
 64	
 65	  const handleActionClick = (eventKey: string): void => {
 66	    if (props.onAction) {
 67	      props.onAction(eventKey as WizardAction, updateLabel.length === 0 ? 'create' : 'update');
 68	    }
 69	  };
 70	
 71	  const getDropdownItemTooltipMessage = (isGatewayAPI: boolean): string => {
 72	    if (serverConfig.deployment.viewOnlyMode) {
 73	      return t('User does not have permission');
 74	    } else if (hasTrafficRouting()) {
 75	      return t('Traffic routing already exists for this service');
 76	    } else if (isGatewayAPI) {
 77	      return t('K8s Gateway API is not enabled');
 78	    } else {
 79	      return t("Traffic routing doesn't exists for this service");
 80	    }
 81	  };
 82	
 83	  const actionItems = SERVICE_WIZARD_ACTIONS.map(eventKey => {
 84	    const isGatewayAPIEnabled =
 85	      eventKey === WIZARD_K8S_REQUEST_ROUTING || eventKey === WIZARD_K8S_GRPC_REQUEST_ROUTING
 86	        ? serverConfig.gatewayAPIEnabled
 87	        : true;
 88	
 89	    const istioWizardKeys = [
 90	      WIZARD_REQUEST_ROUTING,
 91	      WIZARD_FAULT_INJECTION,
 92	      WIZARD_TRAFFIC_SHIFTING,
 93	      WIZARD_REQUEST_TIMEOUTS,
 94	      WIZARD_TCP_TRAFFIC_SHIFTING
 95	    ];
 96	
 97	    const isIstioAPIInstalled = istioWizardKeys.includes(eventKey) ? serverConfig.istioAPIInstalled : true;
 98	
 99	    const enabledItem =
100	      isGatewayAPIEnabled &&
101	      isIstioAPIInstalled &&
102	      !props.isDisabled &&
103	      (!hasTrafficRouting() || (hasTrafficRouting() && updateLabel === eventKey));
104	
105	    const wizardItem = (
106	      <DropdownItem
107	        className={props.className}
108	        key={eventKey}
109	        component="button"
110	        isDisabled={!enabledItem}
111	        onClick={() => handleActionClick(eventKey)}
112	        data-test={eventKey}
113	      >
114	        {t(WIZARD_TITLES[eventKey])}
115	      </DropdownItem>
116	    );
117	
118	    // An Item is rendered under two conditions:
119	    // a) No traffic -> Wizard can create new one
120	    // b) Existing traffic generated by the traffic -> Wizard can update that scenario
121	    // Otherwise, the item should be disabled
122	    if (!enabledItem) {
123	      return (
124	        <Tooltip
125	          key={`tooltip_${eventKey}`}
126	          position={TooltipPosition.left}
127	          content={<>{getDropdownItemTooltipMessage(!isGatewayAPIEnabled)}</>}
128	        >
129	          <div className={optionDisabledStyle}>{wizardItem}</div>
130	        </Tooltip>
131	      );
132	    } else {
133	      return wizardItem;
134	    }
135	  });
136	
137	  // Annotations
138	  if (props.annotations) {
139	    actionItems.push(
140	      <DropdownItem
141	        key={WIZARD_EDIT_ANNOTATIONS}
142	        component="button"
143	        onClick={() => handleActionClick(WIZARD_EDIT_ANNOTATIONS)}
144	        data-test={WIZARD_EDIT_ANNOTATIONS}
145	      >
146	        {serverConfig.kialiFeatureFlags.istioAnnotationAction && !serverConfig.deployment.viewOnlyMode
147	          ? t('Edit Annotations')
148	          : t('View Annotations')}
149	      </DropdownItem>
150	    );
151	  }
152	
153	  actionItems.push(<Divider className={dividerStyle} key="actions_separator" />);
154	
155	  const deleteDisabled = !canDelete(props.istioPermissions) || !hasTrafficRouting() || props.isDisabled;
156	
157	  let deleteDropdownItem = (
158	    <DropdownItem
159	      key={DELETE_TRAFFIC_ROUTING}
160	      component="button"
161	      onClick={() => {
162	        if (props.onDelete) {
163	          props.onDelete(DELETE_TRAFFIC_ROUTING);
164	        }
165	      }}
166	      isDisabled={deleteDisabled}
167	      data-test={DELETE_TRAFFIC_ROUTING}
168	    >
169	      {t('Delete Traffic Routing')}
170	    </DropdownItem>
171	  );
172	
173	  if (deleteDisabled) {
174	    deleteDropdownItem = (
175	      <Tooltip
176	        key={`tooltip_${DELETE_TRAFFIC_ROUTING}`}
177	        position={TooltipPosition.left}
178	        content={<>{getDropdownItemTooltipMessage(false)}</>}
179	      >
180	        <div style={{ display: 'inline-block', cursor: 'not-allowed' }}>{deleteDropdownItem}</div>
181	      </Tooltip>
182	    );
183	  }
184	
185	  actionItems.push(deleteDropdownItem);
186	  const label = updateLabel === '' ? t('Create') : t('Update');
187	
188	  return <DropdownGroup key={`group_${label}`} label={label} className={groupMenuStyle} children={actionItems} />;
189	};

